// Wordle scoring: 2=green, 1=yellow, 0=gray -> 5-char ternary string
function scoreGuess(guess, answer) {
  const res = [0, 0, 0, 0, 0];
  const a = answer.split("");
  for (let i = 0; i < 5; i++) {
    if (guess[i] === answer[i]) { res[i] = 2; a[i] = null; }
  }
  for (let i = 0; i < 5; i++) {
    if (res[i] === 0) {
      const idx = a.indexOf(guess[i]);
      if (idx !== -1) { res[i] = 1; a[idx] = null; }
    }
  }
  return res.join("");
}

const TILE = {
  0: { bg: "#2b3240", fg: "#cfd6e4", label: "absent" },
  1: { bg: "#b89b3e", fg: "#1a1d24", label: "present" },
  2: { bg: "#4f8a5b", fg: "#f3f6f1", label: "correct" },
};

const EMPTY = [0, 0, 0, 0, 0];

// Keep every word consistent with all the guess/marks pairs entered so far.
function matchingWords(dict, history) {
  const patterns = history.map((h) => h.marks.join(""));
  return dict.filter((w) => history.every((h, i) => scoreGuess(h.guess, w) === patterns[i]));
}

// Rank candidate guesses by expected information (entropy) over the candidate
// set. Guessing from that set guarantees a legal, progress-making move.
function rankCandidates(cands) {
  const n = cands.length;
  if (n <= 2) return cands.slice();
  if (n > 700) return cands.slice().sort(); // too many to score cheaply; stay snappy
  const scored = cands.map((g) => {
    const buckets = new Map();
    for (const a of cands) {
      const p = scoreGuess(g, a);
      buckets.set(p, (buckets.get(p) || 0) + 1);
    }
    let h = 0;
    for (const c of buckets.values()) { const pr = c / n; h -= pr * Math.log2(pr); }
    return { g, h };
  });
  scored.sort((a, b) => b.h - a.h || a.g.localeCompare(b.g));
  return scored.map((s) => s.g);
}

// Derive everything on screen from the confirmed guesses. Walks the precomputed
// SALET tree while it can, then falls back to filtering the full dictionary once
// an entered pattern has no branch (e.g. an NYT answer outside Doddle's set).
function computeView(history, dict) {
  let node = SALET_TREE;
  let offTree = false;

  for (let r = 0; r < history.length; r++) {
    const pat = history[r].marks.join("");
    if (pat === "22222") {
      return { status: "solved", word: history[r].guess, guesses: r + 1, offTree, needDict: false };
    }
    if (!offTree) {
      const next = node.next[pat];
      if (next) { node = next; continue; }
      offTree = true; // the tree can't help from here on
    }
  }

  if (!offTree) {
    return { status: "play", guess: node.guess, guesses: history.length + 1, offTree: false, needDict: false };
  }
  if (!dict) {
    return { status: "loading", guesses: history.length + 1, offTree: true, needDict: true };
  }
  const candidates = rankCandidates(matchingWords(dict, history));
  if (candidates.length === 0) {
    return { status: "inconsistent", guesses: history.length + 1, offTree: true, needDict: true };
  }
  return { status: "play", guess: candidates[0], candidates, guesses: history.length + 1, offTree: true, needDict: true };
}

// One grid row: five color-cycling tiles plus its confirm/edit control.
function GridRow({ guess, marks, locked, onCycle, onConfirm, onEdit }) {
  return (
    <div className={`wsx-row ${locked ? "is-locked" : "is-active"}`}>
      <div className="wsx-tiles">
        {guess.split("").map((ch, c) => {
          const t = TILE[marks[c]];
          return (
            <button
              key={c}
              className="wsx-tile"
              style={{ background: t.bg, color: t.fg }}
              disabled={locked}
              onClick={locked ? undefined : () => onCycle(c)}
              aria-label={`${ch}, ${t.label}. Tap to change.`}
            >
              {ch}
            </button>
          );
        })}
      </div>
      <div className="wsx-rowctl">
        {locked
          ? (onEdit ? <button className="wsx-link" onClick={onEdit}>edit</button> : null)
          : <button className="wsx-confirm" onClick={onConfirm}>enter ↵</button>}
      </div>
    </div>
  );
}

export default function App() {
  // Confirmed guesses so far: [{ guess, marks:[..5] }]
  const [history, setHistory] = useState([]);
  // Marks being colored on the current (active) guess
  const [draft, setDraft] = useState(EMPTY);
  // Full word list — lazily loaded only if/when we leave the tree
  const [dict, setDict] = useState(null);
  const [dictFailed, setDictFailed] = useState(false);

  const view = useMemo(() => computeView(history, dict), [history, dict]);

  // Pull in the big dictionary the first time we run off the tree.
  useEffect(() => {
    if (view.needDict && !dict && !dictFailed) {
      import("./words.js").then((m) => setDict(m.WORDS)).catch(() => setDictFailed(true));
    }
  }, [view.needDict, dict, dictFailed]);

  const cycleMark = useCallback((col) => {
    setDraft((prev) => {
      const copy = [...prev];
      copy[col] = (copy[col] + 1) % 3;
      return copy;
    });
  }, []);

  const confirm = useCallback(() => {
    if (view.status !== "play") return;
    setHistory((prev) => [...prev, { guess: view.guess, marks: draft }]);
    setDraft(EMPTY);
  }, [view.status, view.guess, draft]);

  const editRow = useCallback((idx) => {
    setDraft(history[idx].marks);
    setHistory(history.slice(0, idx));
  }, [history]);

  const reset = useCallback(() => {
    setHistory([]);
    setDraft(EMPTY);
  }, []);

  const trail = [...history.map((h) => h.guess), view.status === "play" ? view.guess : null].filter(Boolean);

  return (
    <div className="wsx-root">
      <style>{CSS}</style>

      <header className="wsx-head">
        <div className="wsx-eyebrow">optimal wordle solver · opens with SALET</div>
        <h1 className="wsx-title">The Oracle</h1>
        <p className="wsx-sub">
          Play your real Wordle, then mark the colors you got back here.
          Each move returns the guess that solves in the fewest turns on average.
        </p>
      </header>

      <section className="wsx-verdict" aria-live="polite">
        {view.status === "solved" ? (
          <>
            <div className="wsx-verdict-tag wsx-tag-win">solved{view.offTree ? " · off-tree" : ""}</div>
            <div className="wsx-verdict-word">{view.word}</div>
            <div className="wsx-verdict-meta">{view.guesses} {view.guesses === 1 ? "guess" : "guesses"}</div>
          </>
        ) : view.status === "loading" ? (
          <>
            <div className="wsx-verdict-tag">off the tree</div>
            <div className="wsx-verdict-word wsx-verdict-muted">…</div>
            <div className="wsx-verdict-meta">Loading the full word list to keep solving…</div>
          </>
        ) : view.status === "inconsistent" ? (
          <>
            <div className="wsx-verdict-tag wsx-tag-warn">check the marks</div>
            <div className="wsx-verdict-word wsx-verdict-muted">—</div>
            <div className="wsx-verdict-meta">No word matches every color entered. Tap “edit” on a row to fix a tile.</div>
          </>
        ) : (
          <>
            <div className="wsx-verdict-tag">{view.offTree ? "off-tree · best guess" : "play this next"}</div>
            <div className="wsx-verdict-word">{view.guess}</div>
            <div className="wsx-verdict-meta">
              {view.offTree
                ? `${view.candidates.length} possible ${view.candidates.length === 1 ? "word" : "words"} left`
                : (trail.length <= 1 ? "your opening guess" : `move ${view.guesses} · ${trail.join(" → ")}`)}
            </div>
          </>
        )}
      </section>

      <section className="wsx-grid">
        {history.map((row, rIdx) => (
          <GridRow key={rIdx} guess={row.guess} marks={row.marks} locked onEdit={() => editRow(rIdx)} />
        ))}
        {view.status === "play" && (
          <GridRow key="active" guess={view.guess} marks={draft} locked={false} onCycle={cycleMark} onConfirm={confirm} />
        )}
      </section>

      {view.status === "play" && view.offTree && view.candidates.length > 1 && (
        <section className="wsx-cands">
          <div className="wsx-cands-label">candidates · ranked</div>
          <div className="wsx-cands-list">
            {view.candidates.slice(0, 15).map((w) => (
              <span key={w} className={`wsx-cand ${w === view.guess ? "is-best" : ""}`}>{w}</span>
            ))}
            {view.candidates.length > 15 && (
              <span className="wsx-cand wsx-cand-more">+{view.candidates.length - 15} more</span>
            )}
          </div>
        </section>
      )}

      {dictFailed && (
        <p className="wsx-fine">Couldn’t load the fallback word list (offline?). On-tree solving still works.</p>
      )}

      <footer className="wsx-foot">
        <div className="wsx-legend">
          <span><i style={{ background: TILE[2].bg }} />correct</span>
          <span><i style={{ background: TILE[1].bg }} />present</span>
          <span><i style={{ background: TILE[0].bg }} />absent</span>
        </div>
        <button className="wsx-reset" onClick={reset}>new puzzle</button>
      </footer>

      <p className="wsx-fine">
        Tap a tile to cycle its color. Strategy tree precomputed with Doddle over the standard answer set — most games end in five guesses or fewer. If the real answer falls outside that set, the solver switches to filtering the full word list.
      </p>
    </div>
  );
}

